import{c as a,Q as t,j as s,m as r}from"./chunks/framework.DVkeSyfh.js";const m=JSON.parse('{"title":"Search and Tag Writing","description":"","frontmatter":{},"headers":[],"relativePath":"search-and-tags.md","filePath":"search-and-tags.md","lastUpdated":1780205461000}'),i={name:"search-and-tags.md"};function o(d,e,n,c,l,h){return t(),s("div",null,[...e[0]||(e[0]=[r(`<h1 id="search-and-tag-writing" tabindex="-1">Search and Tag Writing <a class="header-anchor" href="#search-and-tag-writing" aria-label="Permalink to &quot;Search and Tag Writing&quot;">​</a></h1><p>This page covers the search tabs, classifier filtering surface, and the explicit genre-tag write workflow. Use it when the library is already scanned and you want to find useful neighbors, build a temporary set, or decide whether to save MAEST genres back to files.</p><h2 id="search-modes" tabindex="-1">Search Modes <a class="header-anchor" href="#search-modes" aria-label="Permalink to &quot;Search Modes&quot;">​</a></h2><p>The search panel has separate tabs.</p><p>Choose the tab by intent:</p><table tabindex="0"><thead><tr><th>Tab</th><th>What it does</th><th>Use when</th></tr></thead><tbody><tr><td>SONARA</td><td>Searches with explainable playlist features and custom mixer weights.</td><td>You want DJ-transition candidates and control over rhythm, tempo, timbre, dynamics, or harmonic balance.</td></tr><tr><td>MERT</td><td>Searches from selected seed tracks in MERT embedding space.</td><td>You want audio-model similarity without tuning feature weights.</td></tr><tr><td>CLAP</td><td>Searches CLAP audio embeddings from a text prompt.</td><td>You know the sound or mood you want, but do not have a seed track.</td></tr><tr><td>CLASS</td><td>Filters by promoted classifier scores.</td><td>You want a reusable personal signal trained in Rhythm Lab.</td></tr></tbody></table><p>The library browser also has a <code>syncopated</code> preset filter. It selects tracks whose stored MAEST metadata has <code>maest_syncopated_rhythm = true</code> and can be combined with normal library text search and the add-filtered-tracks workflow. Each library row also has a heart button for a local liked-track list. The heart filter in the library controls shows only liked tracks in the same paginated browser, and it can be combined with text search, the syncopated preset, classifier score filters, and add-filtered-tracks. The library controls include a sort-direction button that reverses the currently loaded page in the browser without changing the backend query or stored database order. Pagination controls sit on the left side of the library controls after the filter buttons. The right side shows the total count for the current library view followed by sort-direction and add-visible-tracks controls. The total count and page counter reflect the active text search, preset, liked filter, and classifier score filters.</p><p>The CLASS tab contains classifier controls discovered from promoted <code>models/classifiers/*/model.json</code> metadata. Each promoted classifier can be analyzed from the UI, and its slider filters the library and add-filtered-tracks workflow by <code>track_classifier_scores.score</code>. The top header&#39;s <code>CLASS</code> badge counts tracks that have stored scores for every promoted classifier, so two promoted classifiers require two stored classifier scores on the same track to add one to the badge.</p><h3 id="sonara-search" tabindex="-1">SONARA Search <a class="header-anchor" href="#sonara-search" aria-label="Permalink to &quot;SONARA Search&quot;">​</a></h3><p>SONARA is the primary explainable seed-search path. It sends selected seed tracks, optional lookback tracks, limit, minimum similarity, mixer weights, and modifiers to <code>/api/search/sonara</code>.</p><p>Mixer weights:</p><ul><li><code>timbre</code></li><li><code>rhythm</code></li><li><code>dynamics</code></li><li><code>harmonic</code></li><li><code>tempo</code></li></ul><p>Modifiers:</p><ul><li><code>energy</code></li><li><code>valence</code></li><li><code>acousticness</code></li><li><code>brightness</code></li><li><code>rhythm_density</code></li><li><code>dynamic_range</code></li><li><code>loudness</code></li></ul><p>The backend still accepts preset mode names for compatibility:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>balanced, vibe, sound, dj_transition, custom</span></span></code></pre></div><p>The active UI path uses the custom mixer.</p><p>Start with SONARA when you want explainable results. Increase or reduce mixer weights to make the search lean toward transition fit, rhythmic feel, harmonic similarity, or overall sound.</p><h3 id="mert-search" tabindex="-1">MERT Search <a class="header-anchor" href="#mert-search" aria-label="Permalink to &quot;MERT Search&quot;">​</a></h3><p>MERT seed search sends seed tracks, lookback tracks, limit, and optional minimum similarity to <code>/api/search</code>. It ranks tracks in the MERT embedding space.</p><p>Use MERT after running <code>dj-sim analyze --models mert</code> or the matching selected model in the UI analysis job. If results are empty or stale, check whether the candidate tracks have MERT embeddings.</p><h3 id="clap-text-search" tabindex="-1">CLAP Text Search <a class="header-anchor" href="#clap-text-search" aria-label="Permalink to &quot;CLAP Text Search&quot;">​</a></h3><p>CLAP text search sends a text prompt, limit, optional minimum similarity, and device to <code>/api/search/text</code>. It ranks CLAP audio vectors against a CLAP text vector.</p><p>Concrete English prompts usually work best:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Melancholic minimal house with broken drums, warm chords, no vocals</span></span>
<span class="line"><span>Dark hypnotic techno with sparse percussion and deep rolling bass</span></span>
<span class="line"><span>Organic microhouse with soft pads, plucked textures, and spacious mood</span></span></code></pre></div><p>Use CLAP for exploratory digging. Include musical texture, mood, tempo feel, vocal presence, or instrumentation in the prompt instead of relying only on a genre name.</p><h3 id="class-classifiers" tabindex="-1">CLASS / Classifiers <a class="header-anchor" href="#class-classifiers" aria-label="Permalink to &quot;CLASS / Classifiers&quot;">​</a></h3><p>The CLASS tab is for classifier-driven workflows rather than similarity search. It lists promoted classifiers discovered from <code>models/classifiers/*/model.json</code>:</p><ul><li><code>Analyze &lt;classifier&gt;</code> starts a cancellable classifier job.</li><li>Each classifier slider filters the library server-side by stored classifier score.</li><li>The metadata dialog shows classifier scores, confidence, label, feature set, and model file below SONARA features.</li></ul><p>Promoted classifiers require a promoted model file and feature-complete tracks. They do not analyze audio directly; run SONARA, MERT, and MAEST first for the tracks you want to score.</p><p>Use CLASS filters after scoring a promoted classifier. A high score means the model thinks the track matches that profile&#39;s positive label; it is a workflow hint, not a guarantee.</p><h2 id="tag-writing" tabindex="-1">Tag Writing <a class="header-anchor" href="#tag-writing" aria-label="Permalink to &quot;Tag Writing&quot;">​</a></h2><p>MAEST genre saving writes one normalized semicolon-separated genre string, for example:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Tech House; Minimal; Techno</span></span></code></pre></div><p>MAEST category prefixes such as <code>Electronic---</code> are stripped before writing.</p><p>Format-specific genre fields:</p><ul><li>MP3, WAV, AIFF ID3 tags: <code>TCON</code></li><li>FLAC and Vorbis-style tags: <code>GENRE</code></li><li>MP4, M4A, ALAC: <code>©gen</code></li></ul><p>WAV genre writing uses Mutagen&#39;s <code>WAVE</code> support, saves the <code>TCON</code> value, and verifies that the saved value can be read afterward. It does not run a custom RIFF repair step. If a WAV write or readback fails, that track is reported as failed while the batch continues.</p><p>Use tag writing only after reviewing MAEST labels in the app. It is intended for saving generated genre labels into the standard genre field; it is not a general metadata editor and should not be used to change title, artist, album, BPM, key, or custom tags.</p>`,39)])])}const u=a(i,[["render",o]]);export{m as __pageData,u as default};
